class Solution(object):
    def placeWordInCrossword(self, board, word):
        m, n = len(board), len(board[0])
        word_reversed = word[::-1]
        def can_place(r, c, dr, dc, w):
            for i in range(len(w)):
                nr, nc = r + i * dr, c + i * dc
                if nr < 0 or nr >= m or nc < 0 or nc >= n or board[nr][nc] == '#':
                    return False
                if board[nr][nc] != ' ' and board[nr][nc] != w[i]:
                    return False
            if r - dr >= 0 and r - dr < m and c - dc >= 0 and c - dc < n and board[r-dr][c-dc] != '#':
                return False
            r, c = r + len(w) * dr, c + len(w) * dc
            if r >= 0 and r < m and c >= 0 and c < n and board[r][c] != '#':
                return False
            return True
        for i in range(m):
            for j in range(n):
                if board[i][j] != '#':
                    for w in [word, word_reversed]:
                        if can_place(i, j, 0, 1, w) or can_place(i, j, 1, 0, w):
                            return True
        return False
